var __index = {"config":{"lang":["en","zh"],"separator":"[\\s\\u200b\\-_,:!=\\[\\]()\"`/]+|\\.(?!\\d)|&[lg]t;|(?!\\b)(?=[A-Z][a-z])","pipeline":["stopWordFilter"]},"docs":[{"location":"zh/index.html","title":"GitHub","text":"<p>Bug</p> <p></p>"},{"location":"zh/index.html#navigation","title":"Navigation","text":"<ul> <li> HTML for content and structure</li> <li> JavaScript for interactivity</li> <li> CSS for text running out of boxes</li> <li> Internet Explorer ... huh?</li> </ul> <ul> <li> <p> Set up in 5 minutes</p> <p>Install <code>mkdocs-material</code> with <code>pip</code> and get up and running in minutes</p> <p> Getting started</p> </li> <li> <p> It's just Markdown</p> <p>Focus on your content and generate a responsive and searchable static site</p> <p> Reference</p> </li> <li> <p> Made to measure</p> <p>Change the colors, fonts, language, icons, logo and more with a few lines</p> <p> Customization</p> </li> <li> <p> Open Source, MIT</p> <p>Material for MkDocs is licensed under MIT and available on [GitHub]</p> <p> License</p> </li> </ul>"},{"location":"zh/giscus.html","title":"Giscus","text":"<p>Message Board</p> <p>Welcome to my message board!!</p> <p>Thank you for visiting my website. You are more than welcome to leave your thoughts, suggestions and comments here.</p>"},{"location":"zh/tags.html","title":"Tag","text":"<ul> <li> <p> tips</p> <p>\u4ee5\u4e0b\u662f\u7f51\u7ad9\u6587\u7ae0\u7684\u5206\u7c7b\uff0c\u70b9\u51fb\u53ef\u8df3\u8f6c\u5230\u5bf9\u5e94\u5206\u7c7b\u4e0b\u7684\u6587\u7ae0</p> </li> </ul>"},{"location":"zh/home/about.html","title":"\u5173\u4e8e","text":"<ul> <li> \u5173\u4e8e</li> </ul> <ul> <li> \u60a8\u597d, \u6211\u662f YuiKuen.Yuen!</li> <li> \u5b66\u4e60\u4e2d..<ul> <li> System</li> <li> Network</li> <li> Database</li> <li> Virtualization</li> <li> Cloud Computing</li> <li> DevOps</li> <li> Security Monitoring</li> <li> AI</li> </ul> </li> </ul> <ul> <li> <p> \u63a8\u8350</p> <p> Yuen's Info Silo</p> <p> 111 - 1111</p> <p> 222 - 2222</p> </li> </ul> <ul> <li> <p> Release</p> <p>\u66f4\u65b0\u4e2d...</p> <p>\u2192 \u6240\u6709\u7248\u672c</p> </li> <li> <p> Test</p> <p>\u66f4\u65b0\u4e2d...</p> <p>\u2192 \u4e86\u89e3\u66f4\u591a</p> </li> </ul>"},{"location":"zh/notes/Hugo/hugo-on-ubuntu.html","title":"Ubuntu \u90e8\u7f72 Hugo","text":""},{"location":"zh/notes/MkDocs/beauty-board.html","title":"Top Bulletin Board","text":"<p>Reference Links</p> <p>\u6dfb\u52a0\u9876\u90e8\u516c\u544a\u680f\uff1ahttps://wcowin.work/blog/websitebeauty/header.html</p> <p>docs/overrides \u4e0b\u65b0\u5efa main.html\uff0c\u6811\u72b6\u7ed3\u6784\u5982\u4e0b\uff1a</p> <pre><code>tree -L 2\n.\n\u251c\u2500\u2500 Dockerfile\n\u251c\u2500\u2500 docs\n\u251c\u2500\u2500 mkdocs.yml\n\u251c\u2500\u2500 overrides\n\u2502   \u2514\u2500\u2500 main.html\n</code></pre> <pre><code>&lt;!--\u5de6\u4e0a\u89d2For updates follow--&gt;\n{#-\n  This file was automatically generated - do not edit\n-#}\n{% extends \"base.html\" %}\n{% block extrahead %}\n  &lt;link rel=\"stylesheet\" href=\"{{ 'assets/stylesheets/custom.00c04c01.min.css' | url }}\"&gt;\n{% endblock %}\n{% block announce %}\n  For updates follow &lt;strong&gt;@YuiKuen.Yuen&lt;/strong&gt; on\n  &lt;a rel=\"me\" href=\"https://space.bilibili.com/271768047\" target=\u201c_blank\u201d&gt;\n    &lt;span class=\"twemoji bilibili\"&gt;\n      {% include \".icons/fontawesome/brands/bilibili.svg\" %}\n    &lt;/span&gt;\n    &lt;strong&gt;Bilibili&lt;/strong&gt;\n  &lt;/a&gt;\n  and\n  &lt;a href=\"https://twitter.com/YuikuenY\" target=\u201c_blank\u201d&gt;\n    &lt;span class=\"twemoji x-twitter\"&gt;\n      {% include \".icons/fontawesome/brands/x-twitter.svg\" %}\n    &lt;/span&gt;\n    &lt;strong&gt;X-Twitter&lt;/strong&gt;\n  &lt;/a&gt;\n{% endblock %}\n{% block scripts %}\n  {{ super() }}\n  &lt;script src=\"{{ 'assets/javascripts/custom.9458f965.min.js' | url }}\"&gt;&lt;/script&gt;\n{% endblock %}\n</code></pre>"},{"location":"zh/notes/MkDocs/docker-mkdocs.html","title":"\u4f7f\u7528 Docker \u90e8\u7f72 MkDocs","text":""},{"location":"zh/tools/VMware/vmware-free.html","title":"VMware Free","text":"<p>VMware \u865a\u62df\u673a\u6b63\u5f0f\u5bf9\u4e2a\u4eba\u514d\u8d39\uff0c\u6700\u65b0 Pro \u514d\u6fc0\u6d3b\uff08\u652f\u6280 Win/Mac\uff09</p> <p>VMWare Workstation / Fusion </p> <ul> <li> VMware Fusion Pro - Mac</li> <li> VMware Workstation Pro - Win</li> </ul> <p>\u535a\u901a\u4e8e 2023 \u5e74 11 \u6708\u5b8c\u6210\u4e86 690 \u4ebf\u7f8e\u5143\u5bf9\u4e91\u8ba1\u7b97\u516c\u53f8 VMware \u7684\u6536\u8d2d\uff0c\u5408\u5e76\u540e\u7684 VMware \u5ba3\u5e03\u4e91\u670d\u52a1\u5168\u9762\u53d6\u6d88\u201c\u6c38\u4e45\u8bb8\u53ef\u8bc1\u201d\u5e76\u6539\u4e3a\u8ba2\u9605\u5236\uff0c\u5f15\u8d77\u7528\u6237\u4e0d\u6ee1\u3002</p> <p>\u9664\u6b64\u4e4b\u5916\uff0cVMware \u73b0\u5728\u53c8\u505a\u51fa\u4e86\u4e00\u4e2a\u5c0f\u5c0f\u7684\u4f46\u5f88\u6709\u8bda\u610f\u7684\u8ba9\u6b65\uff1aWorkstation Pro \u548c Fusion Pro \u4ea7\u54c1\u73b0\u5728\u8d77\u5c06\u514d\u8d39\u4f9b\u4e2a\u4eba\u7528\u6237\u4f7f\u7528\u3002</p> <p></p> <p>VMware Workstation Pro \u53ef\u4f9b Windows \u6216 Linux \u7528\u6237\u4f7f\u7528\uff0c\u800c Fusion Pro \u53ef\u4f9b\u57fa\u4e8e Intel CPU \u6216 Apple M \u7cfb\u5217\u5904\u7406\u5668\u7684 Mac \u7535\u8111\u4f7f\u7528\u3002</p> <p>VMware \u7684 Pro \u5e94\u7528\u5c06\u63d0\u4f9b\u4e24\u79cd\u8bb8\u53ef\u6a21\u5f0f\uff1a\u201c\u514d\u8d39\u4e2a\u4eba\u4f7f\u7528\u201d\u4ee5\u53ca\u9488\u5bf9\u4f01\u4e1a\u548c\u7ec4\u7ec7\u7684\u201c\u4ed8\u8d39\u5546\u7528\u8ba2\u9605\u201d\u3002\u7528\u6237\u53ef\u4ee5\u81ea\u884c\u51b3\u5b9a\u662f\u5426\u8ba2\u9605\uff0c\u800c\u4e14 VMware \u4e5f\u5f3a\u8c03\u8fd9\u4e24\u4e2a\u7248\u672c\u4e4b\u95f4\u6ca1\u6709\u529f\u80fd\u5dee\u5f02\uff0c\u552f\u4e00\u7684\u53ef\u89c6\u6027\u5dee\u5f02\u662f\u514d\u8d39\u7248\u672c\u4f1a\u663e\u793a\u201c\u6b64\u4ea7\u54c1\u4ec5\u4f9b\u4e2a\u4eba\u4f7f\u7528\u201d\u63d0\u9192\u3002</p>"},{"location":"zh/tools/VMware/vmware-free.html#_1","title":"\u5982\u4f55\u4e0b\u8f7d","text":"<p>\u7528\u6237\u53ea\u9700\u524d\u5f80 Broadcom \u6ce8\u518c\u4e00\u4e2a\u535a\u901a\u8d26\u53f7\u5373\u53ef\u514d\u8d39\u4e0b\u8f7d\u5e76\u4f7f\u7528 VMware \u8f6f\u4ef6\uff0c\u53e6\u5916\u4e0b\u8f7d\u65f6\u52a1\u5fc5\u9009\u62e9 For Personal User \u7248\u672c</p> <p>VMWare Workstation / Fusion Pro \u865a\u62df\u673a\u4e0b\u8f7d\u5730\u5740\u5982\u4e0b\uff1a</p> <ul> <li>MacOS - VMware Fusion Pro</li> <li>Windos - VMware Workstation Pro</li> </ul> <p>\u8bbf\u95ee\u4e0b\u8f7d\u5730\u5740\u540e\uff0c\u5c31\u53ef\u4ee5\u770b\u5230\u4e00\u4e2a\u5217\u8868\u9875\uff0c\u5176\u4e2d For Personal User \u5c31\u662f\u4e2a\u4eba\u7528\u6237\u514d\u8d39\u7248\u672c\uff0c\u70b9\u51fb\u6700\u65b0\u7248\u672c\u8fdb\u5165\u8be6\u60c5\u9875\u8fdb\u884c\u4e0b\u8f7d\uff08\u6ce8\u610f\u52fe\u9009\u540c\u610f\u534f\u8bae\uff09</p> <p></p> <p></p> <p>\u6700\u540e\u8fd8\u4f1a\u8ba9\u8865\u5145\u5730\u5740\u3001\u7701\u4efd\u3001\u90ae\u7f16\u7b49\u4fe1\u606f\uff0c\u968f\u610f\u4f7f\u7528\u5730\u5740\u751f\u6210\u5668\u586b\u5199\u5373\u53ef</p>"},{"location":"zh/tools/VMware/vmware-free.html#_2","title":"\u5982\u4f55\u5b89\u88c5","text":"<p>\u5b89\u88c5\u8fc7\u7a0b\u5728\u6b64\u7565\u8fc7\uff0c\u4ec5\u5b89\u88c5\u65f6\u52fe\u9009\u300c\u6211\u5e0c\u671b\u6388\u4e88\u5c06 VMWare Workstation / Fusion \u7528\u4e8e\u4e2a\u4eba\u7528\u9014\u7684\u8bb8\u53ef\u300d\u8fd9\u4e2a\u9009\u9879\uff0c\u7136\u540e\u70b9\u51fb\u7ee7\u7eed\u5c31\u5927\u529f\u544a\u6210\u3002</p> <p>\u53c2\u8003\u8d44\u6599</p> <ul> <li>VMware \u865a\u62df\u673a\u4e2a\u4eba\u514d\u8d39\uff1aFusion Pro \u53ca Workstation Pro \u5373\u65e5\u8d77\u53ef\u7528</li> <li>\u91cd\u78c5\uff01VMware \u865a\u62df\u673a\u6b63\u5f0f\u5bf9\u4e2a\u4eba\u514d\u8d39 - \u6700\u65b0 Pro \u514d\u6fc0\u6d3b/\u7f51\u76d8\u4e0b\u8f7d (\u652f\u6301 Win / Mac)</li> </ul>"}]}